// Reload refetches the object from the database
// using the primary keys with an executor.
func (o *WrappedAnnual) Reload(ctx context.Context, exec boil.ContextExecutor) error {
	ret, err := FindWrappedAnnual(ctx, exec, o.UserID, o.Year)
	if err != nil {
		return err
	}

	*o = *ret
	return nil
}

// ReloadAll refetches every row with matching primary key column values
// and overwrites the original object slice with the newly updated slice.
func (o *WrappedAnnualSlice) ReloadAll(ctx context.Context, exec boil.ContextExecutor) error {
	if o == nil || len(*o) == 0 {
		return nil
	}

	slice := WrappedAnnualSlice{}
	var args []interface{}
	for _, obj := range *o {
		pkeyArgs := queries.ValuesFromMapping(reflect.Indirect(reflect.ValueOf(obj)), wrappedAnnualPrimaryKeyMapping)
		args = append(args, pkeyArgs...)
	}

	sql := "SELECT \"wrapped_annual\".* FROM \"wrapped_annual\" WHERE " +
		strmangle.WhereClauseRepeated(string(dialect.LQ), string(dialect.RQ), 1, wrappedAnnualPrimaryKeyColumns, len(*o))

	q := queries.Raw(sql, args...)

	err := q.Bind(ctx, exec, &slice)
	if err != nil {
		return errors.Wrap(err, "entity: unable to reload all in WrappedAnnualSlice")
	}

	*o = slice

	return nil
}

// WrappedAnnualExists checks if the WrappedAnnual row exists.
func WrappedAnnualExists(ctx context.Context, exec boil.ContextExecutor, userID string, year int) (bool, error) {
	var exists bool
	sql := "select exists(select 1 from \"wrapped_annual\" where \"user_id\"=$1 AND \"year\"=$2 limit 1)"

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, sql)
		fmt.Fprintln(writer, userID, year)
	}
	row := exec.QueryRowContext(ctx, sql, userID, year)

	err := row.Scan(&exists)
	if err != nil {
		return false, errors.Wrap(err, "entity: unable to check if wrapped_annual exists")
	}

	return exists, nil
}

// Exists checks if the WrappedAnnual row exists.
func (o *WrappedAnnual) Exists(ctx context.Context, exec boil.ContextExecutor) (bool, error) {
	return WrappedAnnualExists(ctx, exec, o.UserID, o.Year)
}
